// @exec: {"yield_time_ms": 10000, "max_output_tokens": 12000}
const cwd = "/Users/zchee/go/src/github.com/zchee/spanner-manager/.omx/team/resolve-remaining-codegen-expe/worktrees/worker-2";
const memBase = "/Users/zchee/src/github.com/zchee/dotfiles/.config/codex/memories";
const stateRoot = "/Users/zchee/go/src/github.com/zchee/spanner-manager/.omx/state";
const team = "resolve-remaining-codegen-expe";
const worker = "worker-2";

async function sh(command, workdir = cwd, timeout_ms = 20000) {
  return await tools.shell_command({ command, workdir, timeout_ms, login: true });
}

text("Bootstrapping worker protocol, memory quick-pass, and task discovery.\n");

const memSearch = await sh(
  `rg --threads=8 -n "spanner-manager|resolve-remaining-codegen-expe|codegen" "${memBase}/MEMORY.md" || true`,
  cwd,
  20000
);
text("Memory search:\n" + (typeof memSearch === "string" ? memSearch : JSON.stringify(memSearch, null, 2)) + "\n");

const inbox = await sh(`cat "${stateRoot}/team/${team}/workers/${worker}/inbox.md"`, cwd, 20000);
text("Inbox:\n" + (typeof inbox === "string" ? inbox : JSON.stringify(inbox, null, 2)) + "\n");

const workerSkill = await sh(`
for p in "\${CODEX_HOME:-$HOME/.codex}/skills/worker/SKILL.md" \
         "${cwd}/.codex/skills/worker/SKILL.md" \
         "/Users/zchee/go/src/github.com/zchee/spanner-manager/skills/worker/SKILL.md"; do
  if [ -f "$p" ]; then
    echo "==> $p"
    sed -n '1,220p' "$p"
    break
  fi
done
`, cwd, 20000);
text("Worker skill excerpt:\n" + (typeof workerSkill === "string" ? workerSkill : JSON.stringify(workerSkill, null, 2)) + "\n");

const ack = await sh(
  `omx team api send-message --input '{"team_name":"${team}","from_worker":"${worker}","to_worker":"leader-fixed","body":"ACK: ${worker} initialized"}' --json`,
  cwd,
  20000
);
text("ACK result:\n" + (typeof ack === "string" ? ack : JSON.stringify(ack, null, 2)) + "\n");

const identity = await sh(`cat "${stateRoot}/team/${team}/workers/${worker}/identity.json"`, cwd, 20000);
const status = await sh(`cat "${stateRoot}/team/${team}/workers/${worker}/status.json"`, cwd, 20000);
const mailbox = await sh(
  `omx team api mailbox-list --input '{"team_name":"${team}","worker":"${worker}"}' --json`,
  cwd,
  20000
);

text("Identity:\n" + (typeof identity === "string" ? identity : JSON.stringify(identity, null, 2)) + "\n");
text("Status:\n" + (typeof status === "string" ? status : JSON.stringify(status, null, 2)) + "\n");
text("Mailbox:\n" + (typeof mailbox === "string" ? mailbox : JSON.stringify(mailbox, null, 2)) + "\n");

const inboxText = typeof inbox === "string" ? inbox : JSON.stringify(inbox);
const taskIds = [...inboxText.matchAll(/task[- ](\d+)/gi)].map(m => m[1]);
const uniqTaskIds = [...new Set(taskIds)];
text("Discovered task ids: " + JSON.stringify(uniqTaskIds) + "\n");

for (const id of uniqTaskIds) {
  const taskFile = await sh(`cat "${stateRoot}/team/${team}/tasks/task-${id}.json"`, cwd, 20000);
  text(`Task ${id}:\n` + (typeof taskFile === "string" ? taskFile : JSON.stringify(taskFile, null, 2)) + "\n");
}

await tools.update_plan({
  explanation: "Worker bootstrap complete; moving through protocol, task discovery, code exploration, implementation, and verification.",
  plan: [
    { step: "Bootstrap worker protocol: read inbox/skill, ACK leader, inspect mailbox and durable status", status: "completed" },
    { step: "Identify assigned task from inbox/task JSON and claim it safely if unclaimed", status: "in_progress" },
    { step: "Explore relevant codegen failure surfaces and current code ownership boundaries", status: "pending" },
    { step: "Delegate bounded parallel read-only discovery to child agents for faster grounding", status: "pending" },
    { step: "Implement the minimal fix within assigned scope", status: "pending" },
    { step: "Run focused diagnostics/tests/build verification on modified files", status: "pending" },
    { step: "Report concrete progress and evidence back to leader, then continue next feasible work", status: "pending" }
  ]
});

