const worker = "worker-2";

async function sh(command, workdir = cwd, timeout_ms = 20000) {
  return await tools.shell_command({ command, workdir, timeout_ms, login: true });
}

text("Continuing worker protocol: mailbox, task file, claim, and repo inspection.\n");

const mailbox = await sh(
  `omx team api mailbox-list --input '{"team_name":"${team}","worker":"${worker}"}' --json`,
  cwd,
  20000
);
text("Mailbox list:\n" + (typeof mailbox === "string" ? mailbox : JSON.stringify(mailbox, null, 2)) + "\n");

let mailboxData;
try {
  mailboxData = JSON.parse(typeof mailbox === "string" ? mailbox.split("\n").filter(Boolean).slice(-1)[0] : JSON.stringify(mailbox));
} catch {}
if (mailboxData?.data?.messages) {
  for (const msg of mailboxData.data.messages) {
    if (!msg.delivered_at) {
      const mark = await sh(
        `omx team api mailbox-mark-delivered --input '{"team_name":"${team}","worker":"${worker}","message_id":"${msg.message_id}"}' --json`,
        cwd,
        20000
      );
      text(`Marked delivered ${msg.message_id}:\n` + (typeof mark === "string" ? mark : JSON.stringify(mark, null, 2)) + "\n");
    }
  }
}

const taskFile = await sh(`cat "${stateRoot}/team/${team}/tasks/task-2.json"`, cwd, 20000);
text("Task 2 JSON:\n" + (typeof taskFile === "string" ? taskFile : JSON.stringify(taskFile, null, 2)) + "\n");

const claim = await sh(
  `omx team api claim-task --input '{"team_name":"${team}","worker":"${worker}","task_id":"2"}' --json`,
  cwd,
  20000
);
text("Claim result:\n" + (typeof claim === "string" ? claim : JSON.stringify(claim, null, 2)) + "\n");

const transition = await sh(
  `omx team api transition-task-status --input '{"team_name":"${team}","worker":"${worker}","task_id":"2","from":"pending","to":"in_progress"}' --json`,
  cwd,
  20000
);
text("Transition result:\n" + (typeof transition === "string" ? transition : JSON.stringify(transition, null, 2)) + "\n");

const gitStatus = await sh(`git status --short --branch`, cwd, 20000);
const repoLs = await sh(`printf 'PWD=%s\n' "$PWD"; rg --threads=8 -n "expect|Expectation|expected" codegen test . 2>/dev/null | head -n 200`, cwd, 20000);
text("Git status:\n" + (typeof gitStatus === "string" ? gitStatus : JSON.stringify(gitStatus, null, 2)) + "\n");
text("Initial expectation grep:\n" + (typeof repoLs === "string" ? repoLs : JSON.stringify(repoLs, null, 2)) + "\n");

await tools.update_plan({
  explanation: "Task 2 selected. Claiming the task and beginning failure-surface exploration before implementation.",
  plan: [
    { step: "Bootstrap worker protocol: read inbox/skill, ACK leader, inspect mailbox and durable status", status: "completed" },
    { step: "Identify assigned task from inbox/task JSON and claim it safely if unclaimed", status: "completed" },
    { step: "Explore relevant codegen failure surfaces and current code ownership boundaries", status: "in_progress" },
    { step: "Delegate bounded parallel read-only discovery to child agents for faster grounding", status: "pending" },
    { step: "Implement the minimal fix within assigned scope", status: "pending" },
    { step: "Run focused diagnostics/tests/build verification on modified files", status: "pending" },
    { step: "Report concrete progress and evidence back to leader, then continue next feasible work", status: "pending" }
  ]
});

