    { step: "Run focused diagnostics/tests/build verification on modified files", status: "pending" },
    { step: "Report concrete progress and evidence back to leader, then continue next feasible work", status: "pending" }
  ]
});

const statusWrite = await sh(
  `python3 - <<'PY'
from pathlib import Path
from datetime import datetime, timezone
p = Path("/Users/zchee/go/src/github.com/zchee/spanner-manager/.omx/state/team/${team}/workers/${worker}/status.json")
p.write_text('{"state":"running","task_id":"2","claim_token":"${claimToken}","updated_at":"%s"}' % datetime.now(timezone.utc).isoformat().replace("+00:00","Z"))
print(p.read_text())
PY`,
  cwd,
  20000
);
text("Worker status updated:\n" + (typeof statusWrite === "string" ? statusWrite : JSON.stringify(statusWrite, null, 2)) + "\n");

const progressMsg = await sh(
  `omx team api send-message --input '{"team_name":"${team}","from_worker":"${worker}","to_worker":"leader-fixed","body":"Progress: claimed task 2; reproducing remaining codegen expectation failures now"}' --json`,
  cwd,
  20000
);
text("Leader progress ACK:\n" + (typeof progressMsg === "string" ? progressMsg : JSON.stringify(progressMsg, null, 2)) + "\n");

const agents = await Promise.all([
  tools.spawn_agent({
    task_name: "discover_failing_codegen_tests",
    agent_type: "explore",
    message: `Read-only task in ${cwd}. Find the current remaining codegen expectation failures. Run only read-only inspection/tests as needed. Report exact failing test names, file:line anchors, and the minimal production/test files likely involved. Do not edit files.`
  }),
  tools.spawn_agent({
    task_name: "map_codegen_expectation_scope",
    agent_type: "explore",
    message: `Read-only task in ${cwd}. Map the codegen expectation-related tests and templates/helpers most likely to affect expected output snapshots. Report the smallest plausible fix surface and any ownership/scope risks. Do not edit files.`
  })
]);
text("Spawned agents:\n" + JSON.stringify(agents, null, 2) + "\n");

const gitStatus = await sh(`git status --short --branch`, cwd, 20000);
text("Git status:\n" + (typeof gitStatus === "string" ? gitStatus : JSON.stringify(gitStatus, null, 2)) + "\n");

const goTest = await sh(`go test ./codegen -count=1`, cwd, 120000);
text("go test ./codegen -count=1:\n" + (typeof goTest === "string" ? goTest : JSON.stringify(goTest, null, 2)) + "\n");

const rg = await sh(`rg --threads=8 -n "expected|expectation|golden|snapshot|want :=" codegen`, cwd, 30000);
text("Expectation-related grep:\n" + (typeof rg === "string" ? rg : JSON.stringify(rg, null, 2)) + "\n");

const wait = await tools.wait_agent({ timeout_ms: 1000 });
text("Agent wait summary:\n" + JSON.stringify(wait, null, 2) + "\n");

